steps.script:
var main = tree.root.get_node_or_null("Main")
var phase = PhaseManager.current_phase_instance
var c = phase.execute_action({"type": "CONFIRM_TARGETS"})
if not c.get("success", false):
	return "CONFIRM_FAILED:" + str(c.get("error", ""))
if phase.awaiting_reactive_stratagem:
	phase.execute_action({"type": "DECLINE_REACTIVE_STRATAGEM"})
if main and main.shooting_controller and main.shooting_controller.has_method("_deactivate_resolution_dock"):
	main.shooting_controller._deactivate_resolution_dock()
var r = phase.execute_action({"type": "RESOLVE_SHOOTING"})
return "RESOLVE_SUCCESS=" + str(r.get("success", false))

var hit = ""
for e in GameEventLog.entries:
	var t = str(e.get("text", ""))
	if "shooting resolved" in t:
		hit = t
return hit

var found = false
for e in GameEventLog.entries:
	var t = str(e.get("text", ""))
	if "shooting resolved" in t and "Battlewagon Alpha" in t:
		found = true
return found

var bad = false
for e in GameEventLog.entries:
	var t = str(e.get("text", ""))
	if "shooting resolved" in t and "Unknown" in t:
		bad = true
return bad
